import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function UploadPage() {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [videoFile, setVideoFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('access');
    
    if (!token) {
      alert('Сначала войдите в систему');
      navigate('/login');
      return;
    }

    const formData = new FormData();
    formData.append('title', title);
    formData.append('description', description);
    formData.append('video_file', videoFile);

    setUploading(true);
    try {
      await axios.post('http://localhost:8000/api/videos/', formData, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'multipart/form-data'
        }
      });
      navigate('/');
    } catch (error) {
      console.error('Ошибка загрузки:', error);
      alert('Ошибка при загрузке видео');
    } finally {
      setUploading(false);
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', padding: 20 }}>
      <h1 style={{ color: 'white', marginBottom: 30 }}>Загрузить видео</h1>
      <form onSubmit={handleSubmit} style={{ backgroundColor: '#1a1a1a', padding: 30, borderRadius: 12 }}>
        <div style={{ marginBottom: 20 }}>
          <label style={{ color: 'white', display: 'block', marginBottom: 8 }}>Название</label>
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
            style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none' }}
          />
        </div>
        <div style={{ marginBottom: 20 }}>
          <label style={{ color: 'white', display: 'block', marginBottom: 8 }}>Описание</label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            rows={4}
            style={{ width: '100%', padding: 12, borderRadius: 8, border: 'none' }}
          />
        </div>
        <div style={{ marginBottom: 20 }}>
          <label style={{ color: 'white', display: 'block', marginBottom: 8 }}>Видео файл</label>
          <input
            type="file"
            accept="video/*"
            onChange={(e) => setVideoFile(e.target.files[0])}
            required
            style={{ color: 'white' }}
          />
        </div>
        <button type="submit" disabled={uploading} style={{
          width: '100%',
          padding: 12,
          backgroundColor: uploading ? '#666' : '#ff0000',
          color: 'white',
          border: 'none',
          borderRadius: 8,
          fontSize: 16,
          cursor: uploading ? 'not-allowed' : 'pointer'
        }}>
          {uploading ? 'Загрузка...' : 'Загрузить'}
        </button>
      </form>
    </div>
  );
}

export default UploadPage;
